    def handle_light(self, request):
        if request.method == 'GET':
            return self.server.create_response(request, CoapResponseCode.CONTENT, self.light_status)
        elif request.method == 'PUT':
            if request.payload in ['on', 'off']:
                self.light_status = request.payload
                return self.server.create_response(request, CoapResponseCode.CHANGED)
            else:
                return self.server.create_response(request, CoapResponseCode.BAD_REQUEST)

